{
  const bmiRows   = rawBmi.filter(d =&gt;   d.gene_snp_ra === efpVariant && visibleIndices.includes(d.is_index))
  const noBmiRows = rawNoBmi.filter(d =&gt;  d.gene_snp_ra === efpVariant && visibleIndices.includes(d.is_index))
  const efpData   = [
    ...bmiRows.map(d =&gt;   ({ ...d, beta: +d.beta, pvalue: +d.pvalue, analysis: "BMI-Adjusted"   })),
    ...noBmiRows.map(d =&gt; ({ ...d, beta: +d.beta, pvalue: +d.pvalue, analysis: "BMI-Unadjusted" }))
  ]
  if (efpData.length === 0)
    return html`&lt;p style="color:#888;padding:1rem;"&gt;No data for selected variant.&lt;/p&gt;`

  return Plot.plot({
