    },
    x: { label: "Effect size (β)", grid: true },
    y: { domain: visibleIndices.slice().reverse(), label: null, tickSize: 0 },
    marks: [
      Plot.ruleX([0], { stroke: "#bbb", strokeWidth: 1.5 }),
      Plot.ruleY(efpData, {
        x1: 0, x2: "beta", y: "is_index",
        stroke: "analysis", strokeWidth: 3.5, strokeOpacity: 0.45
      }),
      Plot.dot(efpData, {
        x: "beta", y: "is_index", fill: "analysis",
        r: d =&gt; d.pvalue &lt; 0.05 ? 11 : 7,
        opacity: 0.9,
        title: d =&gt; [
          d.is_index + "  (" + d.index_group + ")",
          "Analysis: " + d.analysis,
          "β = " + d.beta.toFixed(5),
          "p = " + d.pvalue.toExponential(3)
        ].join("\n")
      }),
      Plot.text(efpData.filter(d =&gt; d.pvalue &lt; 0.05), {
        x: "beta", y: "is_index",
        text: () =&gt; "*", dy: -1, fontSize: 11, fill: "#222"
      })
    ]
  })
}








Proportion of total genetic effect mediated by BMI, using the Baron–Kenny formula: PM = (β_total − β_direct) / |β_total| × 100. β_total = unadjusted effect; β_direct = BMI-adjusted effect. Only variants with |β_total| ≥ 0.005 across ≥ 3 IS indices are included; individual PMs are clamped to ±300% before taking the median. Top 10 most attenuated and top 10 most amplified variants shown.

{
  if (joinedFiltered.length === 0)
    return html`&lt;p style="color:#888;padding:1rem;"&gt;No data matches current filters.&lt;/p&gt;`

  // Baron-Kenny proportion mediated: PM = (β_total − β_direct) / |β_total|
  // β_total  = beta_no_bmi (unadjusted = total effect)
  // β_direct = beta_bmi    (BMI-adjusted = direct effect)
  // Threshold: |β_total| &gt;= 0.005 to exclude near-zero denominators (suppression cases)
  // Clamp each PM to ±300% before aggregation to prevent extreme outliers
  const all = d3.rollups(
    joinedFiltered.filter(d =&gt; Math.abs(d.beta_no_bmi) &gt;= 0.005),
    v =&gt; {
      const pms = v.map(d =&gt;
        Math.max(-300, Math.min(300,
          (d.beta_no_bmi - d.beta_bmi) / Math.abs(d.beta_no_bmi) * 100
        ))
      )
      if (pms.length &lt; 3) return null
      return {
        median_pm: d3.median(pms),
        n_att:     pms.filter(p =&gt; p &gt; 0).length,
        n_total:   v.length
      }
    },
    d =&gt; d.gene_snp_ra
  )
  .map(([gsr, s]) =&gt; s === null ? null : { gene_snp_ra: gsr, ...s })
  .filter(d =&gt; d !== null && Math.abs(d.median_pm) &lt; 200)
  .sort((a, b) =&gt; b.median_pm - a.median_pm)

  if (all.length === 0)
    return html`&lt;p style="color:#888;padding:1rem;"&gt;Insufficient data after filtering. Try relaxing filters.&lt;/p&gt;`

  // Top 10 most attenuated + top 10 most amplified
  const top10    = all.slice(0, 10)
  const bottom10 = all.slice(-10)
  const med = [...top10, ...bottom10]
    .filter((d, i, arr) =&gt; arr.findIndex(x =&gt; x.gene_snp_ra === d.gene_snp_ra) === i)
    .sort((a, b) =&gt; a.median_pm - b.median_pm)

  const lm = Math.min(260, Math.max(150, d3.max(med, d =&gt; d.gene_snp_ra.length) * 6))

  return Plot.plot({
    width,
    height: Math.max(400, med.length * 24 + 130),
    marginLeft: lm, marginRight: 90, marginBottom: 60,
    style: { fontSize: "11px" },
    color: {
      domain: ["BMI attenuates", "BMI amplifies"],
      range:  ["#8e44ad", "#27ae60"],
      legend: true
    },
    x: { label: "Median proportion mediated by BMI (%)  —  (β total − β direct) / |β total| × 100", grid: true },
    y: {
      label: null, tickSize: 0,
      domain: med.map(d =&gt; d.gene_snp_ra)
    },
    marks: [
      Plot.ruleX([0],   { stroke: "#888", strokeWidth: 1.2 }),
      Plot.ruleX([100], { stroke: "#aaa", strokeWidth: 1, strokeDasharray: "4,3" }),
      Plot.barX(med, {
        x: "median_pm", y: "gene_snp_ra",
        fill: d =&gt; d.median_pm &gt; 0 ? "BMI attenuates" : "BMI amplifies",
        rx: 2,
        title: d =&gt; [
          d.gene_snp_ra,
          "Median proportion mediated: " + d.median_pm.toFixed(1) + "%",
          "Attenuated in: " + d.n_att + "/" + d.n_total + " IS indices"
        ].join("\n")
      }),
      Plot.text(med, {
        x: d =&gt; d.median_pm, y: "gene_snp_ra",
        text: d =&gt; d.median_pm.toFixed(1) + "%",
        dx: d =&gt; d.median_pm &gt;= 0 ? 6 : -6,
        textAnchor: d =&gt; d.median_pm &gt;= 0 ? "start" : "end",
        fontSize: 9, fill: "#333"
      })
    ]
  })
}









